    undirected_closure = nx.Graph()
    for (t1, t2), (cost, path) in shortest_paths.items():
        if undirected_closure.has_edge(t1, t2):
            if cost < undirected_closure[t1][t2]['weight']:
                undirected_closure.add_edge(t1, t2, weight=cost)
        else:
            undirected_closure.add_edge(t1, t2, weight=cost)

    try:
